function isNewSupabaseApiKey(value: string): boolean {
  return value.startsWith("sb_publishable_") || value.startsWith("sb_secret_");
}

function createSupabaseFetch(supabaseKey: string): typeof fetch {
  return async (input, init) => {
    const headers = new Headers(
      typeof Request !== "undefined" && input instanceof Request ? input.headers : undefined,
    );

    if (init?.headers) {
      new Headers(init.headers).forEach((value, key) => headers.set(key, value));
    }

    if (
      isNewSupabaseApiKey(supabaseKey) &&
      headers.get("Authorization") === `Bearer ${supabaseKey}`
    ) {
      headers.delete("Authorization");
    }

    headers.set("apikey", supabaseKey);

    return fetch(input, { ...init, headers });
  };
}

const LOCAL_SESSION_KEY = "nova_local_auth_session_v1";

function getLocalSession() {
  if (typeof window === "undefined") return null;
  try {
    const raw = localStorage.getItem(LOCAL_SESSION_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

function saveLocalSession(email: string, name?: string) {
  if (typeof window === "undefined") return null;
  const userId = "user-" + btoa(email).substring(0, 16);
  const payload = JSON.stringify({ sub: userId, id: userId, email, name: name || email.split("@")[0] });
  const token = `nova-local-jwt-${btoa(payload)}`;
  const user = {
    id: userId,
    email,
    user_metadata: { full_name: name || email.split("@")[0] },
    aud: "authenticated",
    role: "authenticated",
  };
  const session = {
    access_token: token,
    token_type: "bearer",
    expires_in: 3600 * 24 * 365,
    refresh_token: `refresh-${token}`,
    user,
  };
  localStorage.setItem(LOCAL_SESSION_KEY, JSON.stringify(session));
  return { session, user };
}

function clearLocalSession() {
  if (typeof window !== "undefined") {
    localStorage.removeItem(LOCAL_SESSION_KEY);
  }
}

